import re
from datetime import datetime

def sort_strings(lst):
    def extract_number(s):
        return re.findall(r'\d+', s)

    def extract_month(s):
        months = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December']
        for month in months:
            if month in s:
                return months.index(month) + 1
        return None

    def extract_word_number(s):
        word_numbers = {
            'zero': 0, 'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5,
            'six': 6, 'seven': 7, 'eight': 8, 'nine': 9, 'ten': 10, 'eleven': 11,
            'twelve': 12
        }
        for word, number in word_numbers.items():
            if word in s.lower():
                return number
        return None

    def extract_roman(s):
        roman_numerals = {
            'i': 1, 'ii': 2, 'iii': 3, 'iv': 4, 'v': 5, 'vi': 6, 'vii': 7, 'viii': 8, 'ix': 9, 'x': 10
        }
        for numeral, number in roman_numerals.items():
            if numeral in s.lower():
                return number
        return None

    sorted_lst = []
    for s in lst:
        number = extract_number(s)
        month = extract_month(s)
        word_number = extract_word_number(s)
        roman = extract_roman(s)
        if number:
            sorted_lst.append((int(number[0]), s))
        elif month:
            sorted_lst.append((month, s))
        elif word_number:
            sorted_lst.append((word_number, s))
        elif roman:
            sorted_lst.append((roman, s))
        else:
            sorted_lst.append((s, s))

    sorted_lst.sort(key=lambda x: x[0])
    return [x[1] for x in sorted_lst]

print(sort_strings(['iPhone 9', 'iPhone X', 'iPhone 11', 'January', 'February', 'ten', 'nine', '8', '9', '10']))

