        for i, month in enumerate(months):
            if month in s:
                return i + 1
        return None

    def extract_word_number(s):
        word_numbers = {'zero': 0, 'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5, 'six': 6, 'seven': 7, 'eight': 8, 'nine': 9, 'ten': 10, 'eleven': 11, 'twelve': 12}
        for word, number in word_numbers.items():
            if word in s:
                return number
        return None

    def extract_roman_number(s):
        roman_numbers = {'i': 1, 'ii': 2, 'iii': 3, 'iv': 4, 'v': 5, 'vi': 6, 'vii': 7, 'viii': 8, 'ix': 9, 'x': 10, 'xi': 11, 'xii': 12}
        for roman, number in roman_numbers.items():
            if roman in s.lower():
                return number
        return None

    def extract_date(s):
        try:
            date = datetime.strptime(s, '%B %d')
            return date.month, date.day
        except ValueError:
            try:
                date = datetime.strptime(s, '%d %B')
                return date.month, date.day
