import re
from dateutil.parser import parse
import inflect

def sort_strings(strings):
    p = inflect.engine()
    def extract_key(s):
        try:
            # Try to parse as date
            dt = parse(s, fuzzy=True)
            return dt.timestamp()
        except ValueError:
            pass

        # Try to extract number
        match = re.search(r'(\d+)', s)
        if match:
            num = int(match.group())
            partial_match = re.sub(r'\d+', '', s).lower()
            return (num, partial_match)

        # Try to extract worded number
        try:
            num = p.number_to_words(s).lower()
            num = re.sub(r'[^\d]+', '', num)
            if num:
                return int(num)
        except ValueError:
            pass

        # Default to alphabetical order
        return s.lower()

    return sorted(strings, key=extract_key)

